import mpmath
import json
import math

mpmath.mp.dps = 15

def zeta_derivative_over_zeta(s):
    """Compute ζ'(s)/ζ(s) using mpmath"""
    zeta_val = mpmath.zeta(s)
    if abs(zeta_val) < 1e-12:
        return mpmath.mpc(0, 0)
    h = mpmath.mpf('1e-8')
    zeta_deriv = (mpmath.zeta(s + h) - mpmath.zeta(s - h)) / (2 * h)
    return zeta_deriv / zeta_val

def compute_second_moment_integral(T, num_points=200):
    """Compute ∫_T^{2T} |ζ'/ζ(1/2 + it)|² dt using trapezoidal rule"""
    dt = T / num_points
    total = 0.0
    t = T
    prev_val = None
    while t <= 2 * T:
        s = mpmath.mpc(0.5, t)
        try:
            val = zeta_derivative_over_zeta(s)
            current = float(abs(val)**2)
        except:
            current = 0.0
        if prev_val is not None:
            total += 0.5 * (prev_val + current) * dt
        prev_val = current
        t += dt
    return total

def expected_value(T):
    """Expected value: T * (log T)^2 * (1/2 + o(1))"""
    return T * (math.log(T))**2 * 0.5

test_values = [20, 50, 100, 200]
results = []
counterexample = None
max_ratio_error = 0

for T in test_values:
    try:
        computed = compute_second_moment_integral(T, num_points=150)
        expected = expected_value(T)
        ratio = computed / expected if expected > 0 else float('inf')
        ratio_error = abs(ratio - 1)
        if ratio_error > max_ratio_error:
            max_ratio_error = ratio_error
        results.append({
            'T': T,
            'computed': computed,
            'expected': expected,
            'ratio': ratio,
            'ratio_error': ratio_error
        })
    except Exception as e:
        results.append({'T': T, 'error': str(e)})

passed = True
for r in results:
    if 'error' in r:
        passed = False
        counterexample = {'T': r['T'], 'error': r['error']}
        break

if passed and len(results) >= 1:
    final_ratio = results[-1]['ratio']
    if final_ratio < 0.1 or final_ratio > 10:
        passed = False
        counterexample = results[-1]

if results and 'ratio' in results[-1]:
    summary = f"Tested T in {test_values}. Final ratio (computed/expected) = {results[-1]['ratio']:.4f}. Max ratio deviation from 1: {max_ratio_error:.4f}"
else:
    summary = f"Tested T in {test_values}. Computation had errors."

output = {
    'passed': passed,
    'trials': len(test_values),
    'max_error': max_ratio_error,
    'counterexample': counterexample,
    'summary': summary
}

print(json.dumps(output))
